// A77 sound design v1: a tiny WebAudio CHIPTUNE synth — every cue is generated
// at runtime from oscillators + gain envelopes, so there are ZERO audio assets
// and zero licensing surface (original/generated by construction, and the
// square/triangle timbres are period-correct for a 1991 homage). It subscribes
// to session.onChange, maps each fog-filtered event to a cue via sound-map.js,
// and plays it through a master→effects gain honoring the ⚙ split (master +
// effects + music, SEPARATE from reduceAnimation, which never mutes). Two short
// procedural TUNES (creation + splash) loop on the same synth; the full
// soundtrack is later by design. QUALITY is a human listening pass (the user's
// ears) — this file's bar is: builds without throwing, cues fire on the right
// events, sensible defaults.
import { soundForEvent } from './sound-map.js';
import { filterEvents } from '../../engine/visibility.js';

// equal-tempered note frequencies (Hz), A4=440
const NOTE = {
  C3: 130.81, E3: 164.81, G3: 196.00, A3: 220.00,
  C4: 261.63, D4: 293.66, E4: 329.63, F4: 349.23, G4: 392.00, A4: 440.00, B4: 493.88,
  C5: 523.25, D5: 587.33, E5: 659.25, G5: 783.99, C6: 1046.50
};

// A cue recipe: a sequence of notes (freq, delay from cue start, duration),
// each an oscillator of `wave` through a short attack/decay envelope at `gain`.
// Helpers build the common shapes so the table stays readable.
function seq(wave, gain, notes) { return { wave, gain, notes }; }
function chord(wave, gain, freqs, dur) { return seq(wave, gain, freqs.map(f => [f, 0, dur])); }
function arp(wave, gain, freqs, step, dur) { return seq(wave, gain, freqs.map((f, i) => [f, i * step, dur])); }
function fall(wave, gain, from, to, dur) { return seq(wave, gain, [[from, 0, dur * 0.5], [to, dur * 0.5, dur * 0.5]]); }

const RECIPES = {
  'combat-win': chord('square', 0.18, [NOTE.C4, NOTE.E4, NOTE.G4], 0.16),          // a triumphant triad
  'combat-loss': fall('sawtooth', 0.16, NOTE.E4, NOTE.C4, 0.22),                    // a sad drop
  'combat-distant': seq('triangle', 0.05, [[NOTE.C4, 0, 0.06]]),                    // a faint clash
  'capture-win': arp('square', 0.18, [NOTE.C4, NOTE.G4, NOTE.C5], 0.06, 0.14),
  'capture-loss': fall('sawtooth', 0.18, NOTE.C4, NOTE.G3, 0.3),
  'capture-distant': seq('triangle', 0.05, [[NOTE.G3, 0, 0.08]]),
  'found': arp('triangle', 0.16, [NOTE.C4, NOTE.G4], 0.07, 0.14),                   // a settling chime
  'grow': seq('triangle', 0.13, [[NOTE.G4, 0, 0.08], [NOTE.C5, 0.06, 0.1]]),
  'starve': fall('sine', 0.14, NOTE.A3, NOTE.E3, 0.28),
  'build': seq('square', 0.1, [[NOTE.E4, 0, 0.06], [NOTE.G4, 0.06, 0.08]]),
  'disorder': seq('sawtooth', 0.14, [[NOTE.C4, 0, 0.12], [NOTE.B4 / 2, 0.05, 0.14]]), // a dissonant wobble
  'order': arp('triangle', 0.12, [NOTE.E4, NOTE.G4, NOTE.C5], 0.05, 0.1),
  'tech': arp('square', 0.12, [NOTE.G4, NOTE.C5, NOTE.E5, NOTE.G5], 0.045, 0.09),   // a sparkle
  'wonder': arp('square', 0.2, [NOTE.C4, NOTE.E4, NOTE.G4, NOTE.C5, NOTE.E5], 0.08, 0.2), // fanfare
  'age': arp('square', 0.22, [NOTE.C4, NOTE.G4, NOTE.C5, NOTE.E5, NOTE.G5, NOTE.C6], 0.09, 0.26), // the historian's fanfare
  'defeat': fall('sawtooth', 0.2, NOTE.A3, NOTE.C3, 0.5),
  'elimination': seq('triangle', 0.12, [[NOTE.C4, 0, 0.1], [NOTE.G3, 0.1, 0.16]]),
  'barbarian': seq('sawtooth', 0.16, [[NOTE.C3, 0, 0.14], [NOTE.E3, 0.07, 0.14]]),  // a menacing horn
  'victory': arp('square', 0.24, [NOTE.C4, NOTE.E4, NOTE.G4, NOTE.C5, NOTE.G4, NOTE.C5], 0.1, 0.28),
  'gameover': fall('sawtooth', 0.2, NOTE.G3, NOTE.C3, 0.6),
  'government': arp('triangle', 0.14, [NOTE.C4, NOTE.F4, NOTE.A4], 0.07, 0.14),
  'regent': seq('square', 0.08, [[NOTE.G4, 0, 0.05], [NOTE.E4, 0.05, 0.06]])        // a soft robot blip
};

// The two TUNES: short looping note lists [freq, dur] on a mellow triangle.
const TUNES = {
  creation: { wave: 'triangle', gain: 0.09, tempo: 0.34, notes: [
    NOTE.C4, NOTE.E4, NOTE.G4, NOTE.E4, NOTE.A4, NOTE.G4, NOTE.E4, NOTE.C4,
    NOTE.D4, NOTE.F4, NOTE.A4, NOTE.F4, NOTE.G4, NOTE.E4, NOTE.D4, NOTE.C4] },
  splash: { wave: 'triangle', gain: 0.08, tempo: 0.42, notes: [
    NOTE.C4, NOTE.G4, NOTE.E4, NOTE.G4, NOTE.F4, NOTE.A4, NOTE.G4, NOTE.E4,
    NOTE.D4, NOTE.G4, NOTE.C5, NOTE.G4, NOTE.E4, NOTE.G4, NOTE.C4, NOTE.C4] }
};

export function initSound(ctx) {
  const opt = ctx.options;
  let actx = null;      // created lazily (autoplay policy: needs a user gesture)
  let masterGain = null;
  let tuneTimer = null;
  let played = 0;       // cue counter (test hook)

  function ensureContext() {
    if (actx) { if (actx.state === 'suspended') actx.resume(); return actx; }
    const AC = window.AudioContext || window.webkitAudioContext;
    if (!AC) return null;
    actx = new AC();
    masterGain = actx.createGain();
    masterGain.connect(actx.destination);
    return actx;
  }
  // resume the context on the first user gesture (browsers block audio before it)
  const resume = () => { if (actx && actx.state === 'suspended') actx.resume(); };
  window.addEventListener('pointerdown', resume);
  window.addEventListener('keydown', resume);

  function vol(kind) {
    const master = num(opt ? opt.get('soundMaster') : 70, 70) / 100;
    if (kind === 'fx' && opt && opt.get('soundEffects') === false) return 0;
    if (kind === 'music' && opt && opt.get('soundMusic') === false) return 0;
    return master;
  }
  function num(v, d) { const n = parseInt(v, 10); return Number.isFinite(n) ? n : d; }

  // schedule one recipe's notes as enveloped oscillators
  function render(recipe, kind, tuneGain) {
    const c = ensureContext();
    if (!c || masterGain === null) return;
    const g = vol(kind) * (tuneGain !== undefined ? 1 : 1);
    if (g <= 0) return;
    const now = c.currentTime;
    for (const [freq, delay, dur] of recipe.notes) {
      const osc = c.createOscillator();
      const env = c.createGain();
      osc.type = recipe.wave;
      osc.frequency.value = freq;
      const t0 = now + delay;
      const peak = recipe.gain * g * (tuneGain === undefined ? 1 : tuneGain);
      env.gain.setValueAtTime(0.0001, t0);
      env.gain.exponentialRampToValueAtTime(Math.max(peak, 0.0002), t0 + 0.008); // fast attack
      env.gain.exponentialRampToValueAtTime(0.0001, t0 + dur);                    // decay
      osc.connect(env); env.connect(masterGain);
      osc.start(t0); osc.stop(t0 + dur + 0.02);
    }
  }

  function play(id) {
    const recipe = RECIPES[id];
    if (!recipe) return;
    render(recipe, 'fx');
    played += 1;
  }

  // --- music: loop a tune until stopped -------------------------------------
  function playTune(name) {
    const tune = TUNES[name];
    if (!tune) return;
    stopTune();
    let i = 0;
    const stepMs = tune.tempo * 1000;
    const tick = () => {
      if (vol('music') > 0) render({ wave: tune.wave, gain: tune.gain, notes: [[tune.notes[i], 0, tune.tempo * 0.9]] }, 'music', 1);
      i = (i + 1) % tune.notes.length;
    };
    tick();
    tuneTimer = setInterval(tick, stepMs);
  }
  function stopTune() { if (tuneTimer) { clearInterval(tuneTimer); tuneTimer = null; } }

  // --- cue wiring: fog-filtered events → cues -------------------------------
  // (session-optional: the setup screen and the soundboard use tunes-only)
  const cityOwner = (state) => (cid) => (state.cities[cid] ? state.cities[cid].owner : null);
  if (ctx.session && ctx.session.onChange) {
    ctx.session.onChange((state, events) => {
      if (!events || events.length === 0) return;
      // fog gate: only sound what the viewer could actually witness (same as
      // the turn log) — session round events are omniscient
      const seen = filterEvents(state, events, ctx.HUMAN);
      const owner = cityOwner(state);
      for (const e of seen) {
        const id = soundForEvent(e, ctx.HUMAN, owner);
        if (id) play(id);
      }
    });
  }

  return { play, playTune, stopTune, get cuesPlayed() { return played; } };
}
